{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { margin: 12mm 14mm 8mm 14mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 820px; margin: 0 auto; padding: 0; }

  .hotel-logo { max-height: 70px; max-width: 140px; }
  .logo-box {
    display: inline-block; width: 46px; height: 46px;
    background: #1a1a2e; color: #fff; font-size: 16pt; font-weight: 700;
    text-align: center; line-height: 46px; border-radius: 5px;
  }
  .hotel-name { font-size: 14pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7.5pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 14px 0 16px; }

  .section-title {
    font-size: 7.5pt; font-weight: 700; color: #1a1a2e;
    text-transform: uppercase; letter-spacing: 0.6px;
    background: #f1f3f8;
    border-left: 3px solid #1a1a2e;
    border-bottom: 1px solid #d1d5db;
    padding: 5px 9px;
    margin-top: 14px; margin-bottom: 8px;
  }

  /* FILTER BAR */
  .filter-bar { width: 100%; border-collapse: collapse; margin-bottom: 14px; }
  .filter-bar td { padding: 3px 8px; font-size: 8pt; border-bottom: 1px solid #f1f5f9; }
  .filter-bar td:first-child { font-weight: 700; color: #1a1a2e; width: 22%; white-space: nowrap; }
  .filter-bar td:last-child { color: #374151; }

  /* SUMMARY BOX */
  .summary-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .summary-table td { padding: 5px 10px; font-size: 9pt; border-bottom: 1px solid #f1f5f9; }
  .summary-table .s-label { color: #6b7280; width: 60%; }
  .summary-table .s-value { text-align: right; font-weight: 600; color: #1a1a2e; }
  .summary-table .total-row td { background: #f1f3f8; color: #1a1a2e; font-weight: 700; font-size: 9.5pt; border-top: 2px solid #1a1a2e; border-bottom: 1px solid #d1d5db; }
  .summary-table .debit-row td { color: #dc2626; font-weight: 600; }
  .summary-table .credit-row td { color: #15803d; font-weight: 600; }

  /* LEDGER TABLE */
  .ledger-table { width: 100%; border-collapse: collapse; font-size: 8pt; margin-bottom: 4px; }
  .ledger-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .ledger-table thead th { padding: 6px 7px; text-align: left; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; }
  .ledger-table thead th.num { text-align: right; }
  .ledger-table tbody tr:nth-child(even) { background: #f9fafb; }
  .ledger-table tbody td { padding: 6px 7px; border-bottom: 1px solid #f1f5f9; color: #374151; }
  .ledger-table tbody td.num { text-align: right; font-variant-numeric: tabular-nums; }
  .ledger-table tfoot tr { border-top: 2px solid #1a1a2e; background: #f9fafb; }
  .ledger-table tfoot td { padding: 7px 7px; font-weight: 700; color: #1a1a2e; }
  .ledger-table tfoot td.num { text-align: right; }

  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 20px 0 12px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 16px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Guest Ledger</div>
        <div class="doc-subtitle">Transaction Statement</div>
        <div class="doc-ref">
          <strong>Period:</strong> {{ filters.date_from }} &mdash; {{ filters.date_to }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- APPLIED FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="filter-bar" cellpadding="0" cellspacing="0">
    <colgroup><col style="width:22%" /><col style="width:28%" /><col style="width:22%" /><col style="width:28%" /></colgroup>
    <tr>
      <td>Date From</td><td>{{ filters.date_from }}</td>
      <td>Date To</td><td>{{ filters.date_to }}</td>
    </tr>
    <tr>
      <td>Guest</td><td>{{ filters.guest or 'All Guests' }}</td>
      <td>Check-In Status</td><td>{{ filters.checkin_status or 'All' }}</td>
    </tr>
    <tr>
      <td>Room Type</td><td>{{ filters.room_type or 'All Room Types' }}</td>
      <td>Transaction Type</td><td>{{ filters.transaction_type or 'All Transactions' }}</td>
    </tr>
  </table>

  <!-- LEDGER ROWS -->
  <div class="section-title">Transaction Ledger</div>
  {% if rows %}
  <table class="ledger-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th>
        <th>Date</th>
        <th>Guest</th>
        <th>Room</th>
        <th>Type</th>
        <th>Voucher</th>
        <th>Remarks</th>
        <th class="num">Debit</th>
        <th class="num">Credit</th>
        <th class="num">Balance</th>
      </tr>
    </thead>
    <tbody>
      {% for row in rows %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="white-space:nowrap;">{{ row.date or '&mdash;' }}</td>
        <td style="font-weight:600;">{{ row.guest_name or row.guest or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ row.room_number or '&mdash;' }}</td>
        <td style="color:#6b7280;white-space:nowrap;">{{ row.transaction_type or '&mdash;' }}</td>
        <td style="color:#6b7280;font-size:7.5pt;">{{ row.voucher_no or '&mdash;' }}</td>
        <td style="color:#374151;font-size:7.5pt;">{{ row.remarks or '&mdash;' }}</td>
        <td class="num" style="color:{% if row.debit | float > 0 %}#dc2626{% else %}#9ca3af{% endif %};">
          {% if row.debit | float > 0 %}&#x20a6;{{ "{:,.2f}".format(row.debit | float) }}{% else %}&mdash;{% endif %}
        </td>
        <td class="num" style="color:{% if row.credit | float > 0 %}#15803d{% else %}#9ca3af{% endif %};">
          {% if row.credit | float > 0 %}&#x20a6;{{ "{:,.2f}".format(row.credit | float) }}{% else %}&mdash;{% endif %}
        </td>
        <td class="num" style="font-weight:600;color:{% if row.running_balance | float > 0 %}#dc2626{% elif row.running_balance | float < 0 %}#15803d{% else %}#374151{% endif %};">
          &#x20a6;{{ "{:,.2f}".format(row.running_balance | float | abs) }}
          {% if row.running_balance | float < 0 %} Cr{% endif %}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="7">Totals</td>
        <td class="num" style="color:#dc2626;">&#x20a6;{{ "{:,.2f}".format(summary.total_debit | float) }}</td>
        <td class="num" style="color:#15803d;">&#x20a6;{{ "{:,.2f}".format(summary.total_credit | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.2f}".format(summary.closing_balance | float | abs) }}</td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:14px;color:#9ca3af;font-size:8pt;border:1px dashed #e5e7eb;">No transactions found for the selected filters.</p>
  {% endif %}

  <!-- SUMMARY -->
  <div class="section-title">Summary</div>
  <table width="55%" cellpadding="0" cellspacing="0" style="margin-left:45%;">
    <tbody>
      <tr>
        <td style="padding:5px 10px;font-size:9pt;color:#6b7280;border-bottom:1px solid #f1f5f9;">Opening Balance</td>
        <td style="padding:5px 10px;font-size:9pt;text-align:right;font-weight:600;color:#1a1a2e;border-bottom:1px solid #f1f5f9;">&#x20a6;{{ "{:,.2f}".format(summary.opening_balance | float) }}</td>
      </tr>
      <tr>
        <td style="padding:5px 10px;font-size:9pt;color:#dc2626;border-bottom:1px solid #f1f5f9;">Total Charges (Dr)</td>
        <td style="padding:5px 10px;font-size:9pt;text-align:right;font-weight:600;color:#dc2626;border-bottom:1px solid #f1f5f9;">&#x20a6;{{ "{:,.2f}".format(summary.total_debit | float) }}</td>
      </tr>
      <tr>
        <td style="padding:5px 10px;font-size:9pt;color:#15803d;border-bottom:1px solid #f1f5f9;">Total Payments (Cr)</td>
        <td style="padding:5px 10px;font-size:9pt;text-align:right;font-weight:600;color:#15803d;border-bottom:1px solid #f1f5f9;">&#x20a6;{{ "{:,.2f}".format(summary.total_credit | float) }}</td>
      </tr>
      <tr>
        <td style="padding:5px 10px;font-size:9.5pt;font-weight:700;background:#f1f3f8;color:#1a1a2e;border-top:2px solid #1a1a2e;border-bottom:1px solid #d1d5db;">Closing Balance</td>
        <td style="padding:5px 10px;font-size:9.5pt;text-align:right;font-weight:700;background:#f1f3f8;color:#1a1a2e;border-top:2px solid #1a1a2e;border-bottom:1px solid #d1d5db;">&#x20a6;{{ "{:,.2f}".format(summary.closing_balance | float) }}</td>
      </tr>
      <tr>
        <td style="padding:4px 10px;font-size:7.5pt;color:#6b7280;">{{ summary.transaction_count }} transaction(s) &nbsp;&middot;&nbsp; {{ summary.guest_count }} guest(s)</td>
        <td></td>
      </tr>
    </tbody>
  </table>

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          <strong style="color:#374151;">Period: {{ filters.date_from }} to {{ filters.date_to }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
